                  <tr key={c.id} className="border-b hover:bg-gray-50/50 transition"><td className="px-4 py-3"><input type="checkbox" checked={selected.has(c.id)} onChange={() => toggleSelect(c.id)} aria-label={`Seleccionar contrato ${c.id}`} /></td><td className="px-4 py-3"><p className="font-bold">{c.employee.name}</p><p className="text-[10px] text-gray-400">{c.employee.email}</p></td><td className="px-4 py-3">{c.job.title}</td><td className="px-4 py-3 text-xs">{c.contractType?.name}</td><td className="px-4 py-3 text-xs">{c.salary ? `$${c.salary}` : (c.hourlyRate ? `$${c.hourlyRate}/h` : '—')}</td><td className="px-4 py-3"><button onClick={() => toggleActive(c.id, c.isActive)} aria-label={currentActive ? 'Desactivar contrato' : 'Activar contrato'} className={`w-8 h-4 rounded-full relative transition ${currentActive ? 'bg-green-500' : 'bg-gray-200'}`}><span className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition ${currentActive ? 'left-4.5' : 'left-0.5'}`} /></button></td><td className="px-4 py-3 text-xs">{fmt(c.startDate)}</td><td className="px-4 py-3 text-xs">{fmt(c.endDate)}</td><td className="px-4 py-3 flex gap-2"><button onClick={() => saveRow(c.id)} disabled={!isDirty || isSaving} className={`text-xs px-3 py-1 rounded-lg font-bold ${isDirty && !isSaving ? 'bg-black text-white' : 'bg-gray-100 text-gray-400'}`}>{isSaving ? '...' : 'OK'}</button><button onClick={() => openHistory(c.employee.id, c.employee.name)} className="text-xs px-3 py-1 rounded-lg bg-blue-50 text-blue-600 font-bold">Log</button></td></tr>
                )
              })}
            </tbody>
          </table>
        </div>
