              <input type="text" placeholder="Nombre" aria-label="Nombre del almacén" value={officeForm.name} onChange={e => setOfficeForm(f => ({ ...f, name: e.target.value }))} className="form-input w-full" />
              <input type="text" placeholder="Dirección" aria-label="Dirección del almacén" value={officeForm.address} onChange={e => setOfficeForm(f => ({ ...f, address: e.target.value }))} className="form-input w-full" />
              <div className="grid grid-cols-2 gap-3">
                <input type="number" placeholder="Latitud" aria-label="Latitud" value={officeForm.latitude} onChange={e => setOfficeForm(f => ({ ...f, latitude: e.target.value }))} className="form-input w-full" />
                <input type="number" placeholder="Longitud" aria-label="Longitud" value={officeForm.longitude} onChange={e => setOfficeForm(f => ({ ...f, longitude: e.target.value }))} className="form-input w-full" />
              </div>
              <input type="number" placeholder="Radio cobertura (mi)" aria-label="Radio de cobertura en millas" value={officeForm.coverageRadiusMiles} onChange={e => setOfficeForm(f => ({ ...f, coverageRadiusMiles: e.target.value }))} className="form-input w-full" />
              {officeError && <p className="text-red-500 text-sm">{officeError}</p>}
            </div>
            <div className="mt-6 flex justify-end gap-3"><button onClick={() => setOfficeModal(false)} className="px-4 py-2 text-sm font-semibold text-gray-500">Cancelar</button><button onClick={saveOffice} disabled={savingOffice} className="px-4 py-2 text-sm font-bold bg-[var(--color-primary)] text-white rounded-lg">{savingOffice ? '...' : 'Guardar'}</button></div>
          </div>
        </div>
      )}
    </DashboardLayout>
  )
}

'use client'

import { useState } from 'react'

type Mode = 'create' | 'edit' | 'view'

type Role = { id: number; name: string }
type Job = { id: number; title: string }
type ContractType = { id: number; name: string }

type Props = {
    mode: Mode
    initialData?: any
    roles: Role[]
    jobs: Job[]
    contractTypes: ContractType[]
    onSubmit: (data: any) => Promise<void>
    onClose: () => void
}

export function EmployeeForm({
    mode,
    initialData,
    roles,
    jobs,
    contractTypes,
    onSubmit,
    onClose,
}: Props) {
    const isView = mode === 'view'
    const isEdit = mode === 'edit'

    const [loading, setLoading] = useState(false)
    const [error, setError] = useState('')

    const [form, setForm] = useState({
        firstName: initialData?.firstName || '',
        lastName: initialData?.lastName || '',
        identification: initialData?.identification || '',
        email: initialData?.email || '',
        password: '',
        phone: initialData?.phone || '',
        roleId: initialData?.roleId || '',
        status: initialData?.status || 'ACTIVE',
        jobId: initialData?.jobId || '',
        contractTypeId: initialData?.contractTypeId || '',
        salary: initialData?.salary || '',
        hourlyRate: initialData?.hourlyRate || '',
        startDate: initialData?.startDate || '',
        endDate: initialData?.endDate || '',
    })

    function validate() {
        if (
            !form.firstName ||
            !form.lastName ||
            !form.identification ||
            !form.email ||
            (!isEdit && !form.password) ||
            !form.phone ||
            !form.roleId ||
            !form.jobId ||
            !form.contractTypeId ||
            !form.salary ||
            !form.hourlyRate ||
            !form.startDate
        ) {
            return 'Todos los campos obligatorios deben completarse'
        }
        return null
    }

    async function handleSubmit(e: React.FormEvent) {
        e.preventDefault()

        const err = validate()
        if (err) return setError(err)

        setLoading(true)
        setError('')

        try {
            await onSubmit(form)
        } catch (e: any) {
            setError(e.message)
        } finally {
            setLoading(false)
        }
    }

    function getNameById(list: any[], id: any, key: string) {
        return list.find(i => i.id == id)?.[key] || '—'
    }

    return (
        <div className="fixed inset-0 bg-black/50 flex justify-center items-center z-50">
            <div className="bg-white rounded-xl w-full max-w-lg p-6 space-y-4">

                <h2 className="text-xl font-bold">
                    {mode === 'create' && 'Crear empleado'}
                    {mode === 'edit' && 'Editar empleado'}
                    {mode === 'view' && 'Detalle del empleado'}
                </h2>

                {/* 👁️ VIEW MODE */}
                {isView ? (
                    <div className="space-y-2 text-sm">
                        <p><b>Nombre:</b> {form.firstName} {form.lastName}</p>
                        <p><b>Email:</b> {form.email}</p>
                        <p><b>Identificación:</b> {form.identification}</p>
                        <p><b>Teléfono:</b> {form.phone}</p>
                        <p><b>Estado:</b> {form.status}</p>

                        <hr />

                        <p><b>Rol:</b> {getNameById(roles, form.roleId, 'name')}</p>
                        <p><b>Cargo:</b> {getNameById(jobs, form.jobId, 'title')}</p>
                        <p><b>Contrato:</b> {getNameById(contractTypes, form.contractTypeId, 'name')}</p>
                        <p><b>Salario:</b> {form.salary}</p>
                        <p><b>Hora:</b> {form.hourlyRate}</p>
                        <p><b>Inicio:</b> {form.startDate}</p>
                        <p><b>Fin:</b> {form.endDate || '—'}</p>
                    </div>
                ) : (
                    <form onSubmit={handleSubmit} className="space-y-3">

                        <input placeholder="Nombre" value={form.firstName}
                            onChange={e => setForm(f => ({ ...f, firstName: e.target.value }))}
                            className="input" />

                        <input placeholder="Apellido" value={form.lastName}
                            onChange={e => setForm(f => ({ ...f, lastName: e.target.value }))}
                            className="input" />

                        <input placeholder="Identificación" value={form.identification}
                            onChange={e => setForm(f => ({ ...f, identification: e.target.value }))}
                            className="input" />

                        <input placeholder="Email" value={form.email}
                            onChange={e => setForm(f => ({ ...f, email: e.target.value }))}
                            className="input" />

                        <input type="password" placeholder="Contraseña"
                            value={form.password}
                            onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
                            className="input" />

                        <input placeholder="Teléfono" value={form.phone}
                            onChange={e => setForm(f => ({ ...f, phone: e.target.value }))}
                            className="input" />

                        <select value={form.roleId}
                            onChange={e => setForm(f => ({ ...f, roleId: e.target.value }))}>
                            <option value="">Rol</option>
                            {roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                        </select>

                        <select value={form.jobId}
                            onChange={e => setForm(f => ({ ...f, jobId: e.target.value }))}>
                            <option value="">Cargo</option>
                            {jobs.map(j => <option key={j.id} value={j.id}>{j.title}</option>)}
                        </select>

                        <select value={form.contractTypeId}
                            onChange={e => setForm(f => ({ ...f, contractTypeId: e.target.value }))}>
                            <option value="">Contrato</option>
                            {contractTypes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>

                        <input placeholder="Salario" value={form.salary}
                            onChange={e => setForm(f => ({ ...f, salary: e.target.value }))}
                            className="input" />

                        <input placeholder="Tarifa hora" value={form.hourlyRate}
                            onChange={e => setForm(f => ({ ...f, hourlyRate: e.target.value }))}
                            className="input" />

                        <input type="date" value={form.startDate}
                            onChange={e => setForm(f => ({ ...f, startDate: e.target.value }))} />

                        <input type="date" value={form.endDate}
                            onChange={e => setForm(f => ({ ...f, endDate: e.target.value }))} />

                        {error && <p className="text-red-500 text-sm">{error}</p>}

                        <div className="flex gap-2">
                            <button type="button" onClick={onClose}>Cancelar</button>
                            <button disabled={loading}>
                                {loading ? 'Guardando...' : 'Guardar'}
                            </button>
                        </div>
                    </form>
                )}
            </div>
        </div>
    )
}

'use client'

import { useState } from 'react'
import { DashboardLayout } from '@/components/layout/DashboardLayout'
import { NAV_ITEMS } from '@/components/layout/nav-config'
import { useAuth } from '@/context/AuthContext'
import { Pagination } from '@/components/ui/Pagination'
import { useShipments } from '@/lib/admin/shipments/useShipments'
import { STAGES, STAGE_STYLE, Envio, Locker } from '@/types/admin/shipments'
import { shipmentsClient } from '@/lib/api-client/shipments'

function fmtDate(d: string) { return new Date(d).toLocaleDateString('es-ES', { day: '2-digit', month: 'short', year: '2-digit' }) }

function stageBadge(name: string | null) {
  const cls = name ? (STAGE_STYLE[name] ?? 'bg-gray-100 text-gray-600') : 'bg-gray-100 text-gray-400'
  return <span className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${cls}`}>{name ?? 'Sin etapa'}</span>
}

export function EnviosClient() {
  const { token } = useAuth()
  const {
    lockers, lockersTotal, lockersPage, setLockersPage, lockersPageSize, setLockersPageSize, lockersLoading,
    syncing, syncTerm, setSyncTerm, handleSync,
    selectedLocker, setSelectedLocker, envios, enviosTotal, enviosPage, setEnviosPage, enviosPageSize, setEnviosPageSize, enviosLoading,
    envioSearch, setEnvioSearch, loadLockers, loadEnvios
  } = useShipments(token)

  const [editId, setEditId] = useState<number | null>(null)
  const [editTracking, setEditTracking] = useState(''); const [editStage, setEditStage] = useState(''); const [editComment, setEditComment] = useState('')
  const [saving, setSaving] = useState(false); const [showNewEnvio, setShowNewEnvio] = useState(false)
  const [newName, setNewName] = useState(''); const [newDesc, setNewDesc] = useState(''); const [creating, setCreating] = useState(false)

  const startEdit = (e: Envio) => { setEditId(e.id); setEditTracking(e.trackingNumber ?? ''); setEditStage(e.odooStageName ?? ''); setEditComment('') }

  const saveEdit = async (e: Envio) => {
    setSaving(true)
    try {
      await shipmentsClient.updateShipment(token, {
        id: e.id, 
        trackingNumber: editTracking, 
        odooStageName: editStage, 
        comment: editComment.trim() || undefined
      })
      setEditId(null); loadEnvios(); loadLockers()
    } catch (error) {
      console.error(error);
    } finally { setSaving(false) }
  }

  const handleCreateEnvio = async () => {
    if (!selectedLocker || !newName.trim()) return
    setCreating(true)
    try {
      await shipmentsClient.createShipmentForLocker(token, selectedLocker.id, {
        name: newName.trim(), 
        description: newDesc.trim() || undefined
      })
      setShowNewEnvio(false); setNewName(''); setNewDesc(''); loadEnvios(); loadLockers()
    } catch (error) {
      console.error(error);
    } finally { setCreating(false) }
  }

  return (
    <DashboardLayout pageTitle="Gestión de Envíos" navItems={NAV_ITEMS} onReload={loadLockers}>
      <div className="space-y-6">
        <div className="flex flex-wrap items-end justify-between gap-3">
          <div><h2 className="font-titles text-2xl font-extrabold">Casilleros y Envíos</h2><p className="text-gray-500 text-sm">{lockersTotal} casilleros sincronizados</p></div>
          <div className="flex items-center gap-2 flex-wrap">
            <input aria-label="Buscar en Odoo" type="text" value={syncTerm} onChange={e => setSyncTerm(e.target.value)} placeholder="Buscar en Odoo…" className="form-input text-sm w-56" onKeyDown={e => e.key === 'Enter' && !syncing && handleSync()} />
            <button aria-label="Sincronizar datos" onClick={handleSync} disabled={syncing} className="bg-indigo-600 text-white px-4 py-2 rounded-xl font-bold text-sm disabled:opacity-60">{syncing ? 'Sincronizando…' : '🔄 Sincronizar'}</button>
          </div>
        </div>

        <section className="bg-white rounded-xl border shadow-sm overflow-hidden" aria-label="Lista de casilleros">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 border-b"><tr>{['Proyecto / Casillero', 'Cliente', 'Envíos', 'Última sync', ''].map(h => <th key={h} className="px-4 py-3 text-xs text-gray-400 uppercase font-bold">{h}</th>)}</tr></thead>
            <tbody className="divide-y">
              {lockersLoading ? <tr><td colSpan={5} className="p-8 text-center text-gray-400" aria-live="polite">Cargando…</td></tr> : lockers.length === 0 ? <tr><td colSpan={5} className="p-8 text-center text-gray-400">Sin datos</td></tr> : lockers.map(l => (
                <tr tabIndex={0} role="button" aria-pressed={selectedLocker?.id === l.id} onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { setSelectedLocker(l); setEditId(null); } }} key={l.id} className={`hover:bg-indigo-50 cursor-pointer ${selectedLocker?.id === l.id ? 'bg-indigo-50 border-l-4 border-indigo-500' : ''}`} onClick={() => { setSelectedLocker(l); setEditId(null) }}>
                  <td className="px-4 py-3 font-semibold">{l.odooProjectName}</td><td className="px-4 py-3 text-gray-500 text-xs">{l.customerName ?? '—'}</td><td className="px-4 py-3"><span className={`inline-block px-2 py-0.5 rounded-full text-xs font-bold ${l._count.shipments > 0 ? 'bg-indigo-100 text-indigo-700' : 'bg-gray-100 text-gray-400'}`}>{l._count.shipments}</span></td><td className="px-4 py-3 text-xs text-gray-400">{l.lastSyncedAt ? fmtDate(l.lastSyncedAt) : '—'}</td><td className="px-4 py-3 text-right text-indigo-500 text-xs font-bold">{selectedLocker?.id === l.id ? 'Seleccionado ›' : 'Ver envíos ›'}</td>
                </tr>
              ))}
            </tbody>
          </table>
          <div className="px-5 py-4 border-t"><Pagination page={lockersPage} pageSize={lockersPageSize} totalItems={lockersTotal} onPageChange={setLockersPage} onPageSizeChange={setLockersPageSize} /></div>
        </section>

        {selectedLocker && (
          <section className="bg-white rounded-xl border shadow-sm overflow-hidden" aria-label={`Envíos del casillero ${selectedLocker.odooProjectName}`}>
            <div className="px-5 py-3 border-b flex flex-wrap items-center justify-between gap-3">
              <div><h3 className="font-bold text-gray-700">Envíos — <span className="text-indigo-600">{selectedLocker.odooProjectName}</span></h3><p className="text-xs text-gray-400">{enviosTotal} total</p></div>
              <div className="flex items-center gap-2 flex-wrap">
                <input aria-label="Buscar envíos" type="text" value={envioSearch} onChange={e => setEnvioSearch(e.target.value)} placeholder="Buscar envíos…" className="form-input text-sm w-48" />
                <button aria-label="Nuevo envío" onClick={() => setShowNewEnvio(!showNewEnvio)} className="bg-indigo-600 text-white px-3 py-1.5 rounded-lg font-bold text-sm">+ Nuevo</button>
                <button aria-label="Cerrar envíos" onClick={() => setSelectedLocker(null)} className="text-gray-400 hover:text-gray-700 text-xl">×</button>
              </div>
            </div>

            {showNewEnvio && (
              <div className="px-5 py-4 bg-indigo-50 border-b flex flex-wrap gap-3 items-end">
                <div className="flex-1"><label className="text-xs text-gray-500 font-bold block mb-1">Nombre *</label><input aria-label="Nombre del envío" type="text" value={newName} onChange={e => setNewName(e.target.value)} className="form-input text-sm w-full" /></div>
                <div className="flex-1"><label className="text-xs text-gray-500 font-bold block mb-1">Descripción</label><input aria-label="Descripción del envío" type="text" value={newDesc} onChange={e => setNewDesc(e.target.value)} className="form-input text-sm w-full" /></div>
                <button aria-label="Crear envío" onClick={handleCreateEnvio} disabled={creating || !newName.trim()} className="bg-indigo-600 text-white px-4 py-2 rounded-lg font-bold text-sm disabled:opacity-60">Crear</button>
              </div>
            )}

            <div className="overflow-x-auto"><table className="w-full text-sm text-left"><thead className="bg-gray-50 border-b"><tr>{['#', 'Nombre', 'Etapa', 'Tracking', 'Fecha', 'Acciones'].map(h => <th key={h} className="px-4 py-3 text-xs text-gray-400 uppercase font-bold">{h}</th>)}</tr></thead>
              <tbody className="divide-y">
                {enviosLoading ? <tr><td colSpan={6} className="p-8 text-center text-gray-400" aria-live="polite">Cargando…</td></tr> : envios.map(e => editId === e.id ? (
                  <tr key={e.id} className="bg-indigo-50"><td className="px-4 py-3 font-bold text-gray-500">#{e.odooTaskId ?? e.id}</td><td className="px-4 py-3 font-semibold text-gray-700">{e.odooTaskName}</td><td className="px-4 py-3"><select aria-label="Etapa del envío" value={editStage} onChange={ev => setEditStage(ev.target.value)} className="form-input text-sm">{STAGES.map(s => <option key={s} value={s}>{s}</option>)}</select></td><td className="px-4 py-3"><input type="text" aria-label="Tracking" value={editTracking} onChange={ev => setEditTracking(ev.target.value)} placeholder="Tracking" className="form-input text-sm w-32 mb-1" /><input type="text" aria-label="Nota" value={editComment} onChange={ev => setEditComment(ev.target.value)} placeholder="Nota" className="form-input text-sm w-32" /></td><td className="px-4 py-3 text-xs text-gray-400">{fmtDate(e.createdAt)}</td><td className="px-4 py-3 flex gap-2"><button aria-label="Guardar envío" onClick={() => saveEdit(e)} disabled={saving} className="bg-indigo-600 text-white text-xs px-3 py-1 rounded-lg font-bold">{saving ? '…' : 'OK'}</button><button aria-label="Cancelar edición" onClick={() => setEditId(null)} className="text-xs text-gray-500">X</button></td></tr>
                ) : (
                  <tr key={e.id} className="hover:bg-gray-50 transition"><td className="px-4 py-3 text-gray-400 text-xs">#{e.odooTaskId ?? e.id}</td><td className="px-4 py-3 font-semibold text-gray-800">{e.odooTaskName}</td><td className="px-4 py-3">{stageBadge(e.odooStageName)}</td><td className="px-4 py-3 font-mono text-xs text-blue-600">{e.trackingNumber ?? '—'}</td><td className="px-4 py-3 text-xs text-gray-400">{fmtDate(e.createdAt)}</td><td className="px-4 py-3"><button aria-label={`Editar envío ${e.odooTaskName}`} onClick={() => startEdit(e)} className="text-xs border border-indigo-200 text-indigo-600 px-3 py-1 rounded-lg font-bold">Editar</button></td></tr>
                ))}
              </tbody>
            </table></div>
            <div className="px-5 py-4 border-t"><Pagination page={enviosPage} pageSize={enviosPageSize} totalItems={enviosTotal} onPageChange={setEnviosPage} onPageSizeChange={setEnviosPageSize} /></div>
          </section>
        )}
      </div>
    </DashboardLayout>
  )
}

interface OdooModalProps {
  isOpen: boolean
  onClose: () => void
  searchQuery: string
  setSearchQuery: (q: string) => void
  isSearching: boolean
  customers: any[]
  selectedCustomer: any | null
  setSelectedCustomer: (c: any | null) => void
  isSending: boolean
  error: string
  success: string
  onSend: () => void
}

export function OdooModal({
  isOpen, onClose, searchQuery, setSearchQuery, isSearching,
  customers, selectedCustomer, setSelectedCustomer,
  isSending, error, success, onSend
}: OdooModalProps) {
  if (!isOpen) return null

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
        {/* Modal Header */}
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-[#714B67]/5">
          <div>
            <h3 className="font-titles text-xl font-bold text-[#714B67]">Vincular Cliente Odoo</h3>
            <p className="font-subtitles text-xs text-gray-500 mt-1">Busca y selecciona el cliente para la cotización</p>
          </div>
          <button
            onClick={onClose}
            className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-400"
          >
            ✕
          </button>
        </div>

        {/* Modal Body */}
        <div className="p-6 flex flex-col gap-5">
          {/* Search Input */}
          <div className="relative">
            <input
              type="text"
              placeholder="Buscar por nombre, email o CC..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full border-2 border-gray-100 rounded-2xl px-5 py-4 pl-12 text-sm font-subtitles outline-none focus:border-[#714B67] transition-all"
              autoFocus
            />
            <span className="absolute left-5 top-1/2 -translate-y-1/2 text-xl">🔍</span>
            {isSearching && (
              <div className="absolute right-5 top-1/2 -translate-y-1/2">
                <div className="w-5 h-5 border-2 border-[#714B67] border-t-transparent rounded-full animate-spin"></div>
              </div>
            )}
          </div>

          {/* Results List */}
          <div className="max-h-[300px] overflow-y-auto pr-1 flex flex-col gap-2">
            {customers.length > 0 ? (
              customers.map((customer) => (
                <button
                  key={customer.id}
                  onClick={() => setSelectedCustomer(customer)}
                  className={`flex flex-col gap-1 p-4 rounded-2xl border-2 text-left transition-all ${selectedCustomer?.id === customer.id
                      ? 'border-[#714B67] bg-[#714B67]/5'
                      : 'border-gray-50 hover:border-gray-200 hover:bg-gray-50'
                    }`}
                >
                  <div className="flex justify-between items-start">
                    <span className="font-titles font-bold text-gray-900">{customer.name}</span>
                    <span className="text-[10px] font-bold bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full uppercase">ID: {customer.id}</span>
                  </div>
                  <div className="flex flex-col text-xs text-gray-500 font-subtitles">
                    <span>📧 {customer.email}</span>
                    <span>🆔 CC/NIT: {customer.vat}</span>
                  </div>
                </button>
              ))
            ) : searchQuery.length >= 3 && !isSearching ? (
              <div className="py-10 text-center">
                <p className="text-gray-400 font-subtitles text-sm">No se encontraron clientes que coincidan.</p>
              </div>
            ) : !searchQuery ? (
              <div className="py-10 text-center">
                <p className="text-gray-300 font-subtitles text-sm">Empieza a escribir para buscar...</p>
              </div>
            ) : null}
          </div>

          {/* Messages */}
          {error && (
            <div className="bg-red-50 text-red-600 text-xs p-3 rounded-xl border border-red-100 font-subtitles">
              ⚠️ {error}
            </div>
          )}
          {success && (
            <div className="bg-green-50 text-green-600 text-xs p-3 rounded-xl border border-green-100 font-subtitles animate-bounce">
              ✅ {success}
            </div>
          )}
        </div>

        {/* Modal Footer */}
        <div className="p-6 bg-gray-50 border-t border-gray-100 flex gap-3">
          <button
            onClick={onClose}
            className="flex-1 py-3 px-4 rounded-xl text-sm font-bold font-subtitles text-gray-500 hover:bg-gray-100 transition-colors"
          >
            Cancelar
          </button>
          <button
            onClick={onSend}
            disabled={!selectedCustomer || isSending}
            className={`flex-1 py-3 px-4 rounded-xl text-sm font-bold font-subtitles text-white shadow-lg transition-all ${!selectedCustomer || isSending
                ? 'bg-gray-300 cursor-not-allowed'
                : 'bg-[#714B67] hover:brightness-110 active:scale-95'
              }`}
          >
            {isSending ? (
              <div className="flex items-center justify-center gap-2">
                <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                Enviando...
              </div>
            ) : (
              'Confirmar Envío'
            )}
          </button>
        </div>
      </div>
    </div>
  )
}

interface AttendanceKpisProps {
  hoursToday: string
  attendance: any
  pauseCount: number
  stateLabel: string
}

export function AttendanceKpis({ hoursToday, attendance, pauseCount, stateLabel }: AttendanceKpisProps) {
  const cards = [
    { icon: '⏱️', label: 'Horas hoy', value: `${hoursToday}h` },
    { icon: '✅', label: 'Sesiones', value: attendance ? '1' : '0' },
    { icon: '⏸️', label: 'Pausas', value: pauseCount },
    { icon: '📍', label: 'Estado', value: stateLabel },
  ]

  return (
    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
      {cards.map(card => (
        <div key={card.label} className="flex items-center gap-3 bg-[var(--color-nc-dark)] rounded-2xl px-5 py-4">
          <div className="w-10 h-10 rounded-xl bg-[var(--color-nc-blue)] flex items-center justify-center text-lg flex-shrink-0">
            {card.icon}
          </div>
          <div>
            <p className="font-subtitles text-[11px] text-white/60 uppercase tracking-wide">{card.label}</p>
            <p className="font-titles text-xl font-extrabold text-white leading-tight">{card.value}</p>
          </div>
        </div>
      ))}
    </div>
  )
}

