'use client'
import { useEffect, useMemo, useState } from 'react'

type Country = 'CO' | 'MX'
type City = { id: number; city: string; department: string | null }

export function Calculator() {
  const [country, setCountry] = useState<Country>('CO')
  const [allCities, setAllCities] = useState<City[]>([])
  const [flatRate, setFlatRate] = useState<{ enabled: boolean; price: number }>({ enabled: false, price: 0 })
  const [citiesLoading, setCitiesLoading] = useState(false)
  const [dept, setDept] = useState('')
  const [cityId, setCityId] = useState('')
  const [dims, setDims] = useState({ h: '', w: '', l: '' })
  const [weight, setWeight] = useState('')
  const [declared, setDeclared] = useState('')
  const [pickup, setPickup] = useState('0')
  const [total, setTotal] = useState<number | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  const parse = (v: string) => parseFloat(v.replace(',', '.')) || 0
  const volWeight = Math.ceil((parse(dims.h) * parse(dims.w) * parse(dims.l)) / 153)

  // Fetch all cities whenever country changes
  useEffect(() => {
    setCitiesLoading(true)
    setTotal(null)
    setError('')
    setDept('')
    setCityId('')
    fetch(`/api/cotizaciones/ciudades?country=${country}`)
      .then(r => r.json())
      .then(data => {
        setAllCities(data.data ?? [])
        setFlatRate({ enabled: Boolean(data.flatRateEnabled), price: Number(data.flatRatePrice) })
      })
      .catch(() => { })
      .finally(() => setCitiesLoading(false))
  }, [country])

  // Unique sorted departments derived from allCities
  const departments = useMemo(() => {
    const seen = new Set<string>()
    const list: string[] = []
    for (const c of allCities) {
      const d = c.department ?? ''
      if (d && !seen.has(d)) { seen.add(d); list.push(d) }
    }
    return list.sort()
  }, [allCities])

  // Cities filtered by selected department
  const filteredCities = useMemo(
    () => dept ? allCities.filter(c => c.department === dept) : [],
    [allCities, dept],
  )

  const handleCalc = async () => {
    if (!weight || !dims.h || !dims.w || !dims.l || declared === '') {
      setError('Completa peso, dimensiones y valor declarado')
      return
    }
    if (!flatRate.enabled && !cityId) {
      setError('Selecciona un departamento y una ciudad')
      return
    }
    setError('')
    setLoading(true)
    try {
      const body: Record<string, unknown> = {
        country,
        actualWeightLb: parse(weight),
        heightIn: parse(dims.h),
        lengthIn: parse(dims.l),
        widthIn: parse(dims.w),
        declaredValueUsd: parse(declared),
        pickupMiles: parse(pickup),
      }
      if (!flatRate.enabled && cityId) body.destinationCityId = Number(cityId)

      const res = await fetch('/api/cotizaciones/calcular', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      })
      const data = await res.json()
      if (!res.ok) {
        setTotal(null)
        setError(data.message ?? 'Error al calcular')
        return
      }
      setTotal(data.total)
    } catch {
      setTotal(null)
      setError('Error de conexión')
    }
    finally { setLoading(false) }
  }

  const isValid = weight && dims.h && dims.w && dims.l && declared !== '' && (flatRate.enabled || cityId)

  const inp = 'w-full rounded-[var(--radius-md)] border border-slate-200 bg-white px-2 py-1.5 text-xs shadow-[var(--shadow-sm)] outline-none focus:border-[var(--color-secondary)] focus:ring-2 focus:ring-blue-100'
  const lbl = 'mb-0.5 block text-[9px] font-extrabold uppercase tracking-widest text-slate-600'
  const sec = 'rounded-[var(--radius-md)] border border-slate-200 bg-white p-2'

  return (
    <section className="w-full max-w-md mx-auto rounded-[24px] border border-slate-200 bg-white shadow-[var(--shadow-md)]">
      <div className="px-4 pt-3">
        <h2 className="text-base font-black uppercase text-[var(--color-foreground)]">Calcular envío</h2>
      </div>
      <div className="p-3">
        <div className="mb-3 grid grid-cols-2 gap-1 bg-slate-100 p-1 rounded-[var(--radius-md)]">
          {(['CO', 'MX'] as Country[]).map(c => (
            <button
              key={c}
              onClick={() => { setCountry(c); setTotal(null); setError('') }}
              className={`py-1 text-xs font-bold rounded-[var(--radius-sm)] ${country === c ? 'bg-[var(--color-secondary)] text-white' : 'text-slate-600'}`}
            >
              {c === 'CO' ? '🇨🇴 Colombia' : '🇲🇽 México'}
            </button>
          ))}
        </div>

        <div className="grid gap-2">
          {!flatRate.enabled && (
            <div className={sec}>
              {citiesLoading ? (
                <p className="text-xs text-slate-400">Cargando ciudades...</p>
              ) : (
                <div className="grid grid-cols-2 gap-2">
                  <div>
                    <label className={lbl}>Departamento</label>
                    <select
                      value={dept}
                      onChange={e => { setDept(e.target.value); setCityId(''); setError('') }}
                      className={inp}
                    >
                      <option value="">Seleccionar</option>
                      {departments.map(d => (
                        <option key={d} value={d}>{d}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className={lbl}>Ciudad</label>
                    <select
                      value={cityId}
                      onChange={e => { setCityId(e.target.value); setError('') }}
                      className={inp}
                      disabled={!dept}
                    >
                      <option value="">{dept ? 'Seleccionar' : '— elige depto —'}</option>
                      {filteredCities.map(c => (
                        <option key={c.id} value={c.id}>{c.city}</option>
                      ))}
                    </select>
                  </div>
                </div>
              )}
            </div>
          )}

          {flatRate.enabled && (
            <div className={`${sec} text-xs text-slate-500`}>
              Ciudad: tarifa única USD {flatRate.price.toFixed(2)}
            </div>
          )}

          <div className={sec}>
            <label className={lbl}>Dimensiones (pulgadas)</label>
            <div className="grid grid-cols-3 gap-1">
              {(['h', 'w', 'l'] as const).map(k => {
                const labels = { h: 'Alto', w: 'Ancho', l: 'Largo' }
                return (
                  <div key={k}>
                    <span className="block text-center text-[8px] text-slate-500">{labels[k]}</span>
                    <input
                      value={dims[k]}
                      onChange={e => /^[0-9.,]*$/.test(e.target.value) && setDims(p => ({ ...p, [k]: e.target.value }))}
                      className={`${inp} text-center`}
                    />
                  </div>
                )
              })}
            </div>
          </div>
          <div className={sec}>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className={lbl}>Peso (lb)</label>
                <input
                  value={weight}
                  onChange={e => /^[0-9.,]*$/.test(e.target.value) && setWeight(e.target.value)}
                  className={inp}
                />
              </div>
              <div>
                <label className={lbl}>Valor declarado (USD)</label>
                <input
                  type="number"
                  value={declared}
                  onChange={e => setDeclared(e.target.value)}
                  className={inp}
                  placeholder="0"
                  min="0"
                  max="200"
                  step="1"
                />
              </div>

            </div>
          </div>
          <div className={sec}>
            <div className="bg-slate-50 rounded-[var(--radius-md)] flex flex-col justify-center items-center text-xs">
              <span className="text-[8px] text-slate-500">Vol (lb)</span>
              <span className="font-black text-[var(--color-secondary)]">{volWeight}</span>
            </div>
          </div>

          {error && (
            <div
              role="alert"
              aria-live="polite"
              className="flex items-start gap-2 rounded-[var(--radius-md)] border border-red-300 bg-red-50 px-3 py-2"
            >
              <span aria-hidden="true" className="text-sm leading-none">⚠️</span>
              <p className="flex-1 text-[11px] font-semibold text-red-700">{error}</p>
              <button
                type="button"
                onClick={() => setError('')}
                className="text-red-400 hover:text-red-600 text-sm leading-none"
                aria-label="Cerrar"
              >
                ×
              </button>
            </div>
          )}

          <button
            onClick={handleCalc}
            disabled={!isValid || loading}
            className={`btn-primary w-full py-2 text-xs font-bold transition-opacity ${(!isValid || loading) ? 'opacity-50 cursor-not-allowed' : ''}`}
          >
            {loading ? 'Calculando...' : 'Calcular'}
          </button>

          {total !== null && (
            <div className="mt-2 p-3 rounded-[var(--radius-lg)] text-white text-center bg-gradient-to-r from-[var(--color-secondary)] to-[var(--color-primary)]">
              <p className="text-[9px] uppercase tracking-widest opacity-75 mb-1">Total estimado</p>
              <p className="text-lg font-black">USD {total.toFixed(2)}</p>
            </div>
          )}
        </div>
      </div>
    </section>
  )
}

'use client'

import Link from 'next/link'
import { usePathname } from 'next/navigation'
import { ReactNode } from 'react'

export interface NavItem {
  label: string
  href: string
  icon: ReactNode
  roles?: string[]
  section?: string
}

interface SidebarProps {
  items: NavItem[]
  userRole: string
  systemName?: string
  systemSub?: string
  isOpen: boolean
  onClose: () => void
}

export function Sidebar({
  items,
  userRole,
  systemName = 'N-Cargo',
  systemSub = 'Admin Panel',
  isOpen,
  onClose,
}: SidebarProps) {
  const pathname = usePathname()

  const visible = items.filter(
    item => !item.roles || item.roles.includes(userRole)
  )

  return (
    <>
      {/* Mobile overlay */}
      {isOpen && (
        <div
          className="fixed inset-0 z-40 bg-black/50 md:hidden"
          onClick={onClose}
          aria-hidden="true"
        />
      )}

      <aside
        className={`
          w-[240px] min-h-screen bg-[var(--color-foreground)]/98 backdrop-blur-md border-r border-white/10 shadow-lg shadow-black/30 flex flex-col
          fixed top-0 left-0 z-50
          transition-transform duration-300 ease-in-out
          ${isOpen ? 'translate-x-0' : '-translate-x-full'}
          md:translate-x-0
        `}
      >
        {/* Logo */}
        <div className="h-[80px] px-5 border-b border-white/10 flex items-center shrink-0">
          <Link href="/" aria-label="N-Cargo" className="rounded-[var(--radius-md)] focus-visible:ring-3 focus-visible:ring-[var(--color-primary)] outline-none block w-full">
            <img src="/images/logos/77.PNG" alt="N-Cargo Admin" className="h-[45px] w-auto object-contain rounded-[var(--radius-md)]" width={100} height={45} />
          </Link>
        </div>

        {/* Navigation */}
        <nav className="flex-1 py-2 overflow-y-auto">
          {visible.map((item, idx) => {
            const isActive =
              pathname === item.href ||
              (item.href !== '/' && pathname.startsWith(item.href))

            const prevSection = idx > 0 ? visible[idx - 1].section : undefined
            const showSectionHeader = item.section && item.section !== prevSection

            return (
              <div key={item.href}>
                {showSectionHeader && (
                  <div className="px-4 pt-4 pb-1">
                    <span className="font-subtitles text-[10px] uppercase tracking-widest text-white/40 font-semibold">
                      {item.section}
                    </span>
                  </div>
                )}
                <Link
                  href={item.href}
                  onClick={onClose}
                  aria-current={isActive ? 'page' : undefined}
                  className={`
                    flex items-center gap-3 px-4 py-2 mx-2 my-1 rounded-md
                    text-sm font-subtitles transition-all duration-200
                    focus-visible:outline focus-visible:outline-2 focus-visible:outline-[var(--color-nc-red)]
                    ${isActive
                      ? 'bg-white/10 text-white font-semibold border-l-4 border-[var(--color-nc-red)]'
                      : 'text-white/75 hover:text-white hover:bg-white/10'
                    }
                  `}
                >
                  <span className={`
                    w-8 h-8 flex items-center justify-center rounded-md text-sm flex-shrink-0
                    ${isActive ? 'bg-[var(--color-nc-blue)] text-white' : 'bg-white/10 text-white'}
                  `}>
                    {item.icon}
                  </span>
                  <span className="flex-1">{item.label}</span>
                </Link>
              </div>
            )
          })}
        </nav>
      </aside>
    </>
  )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { useDebounce } from '@/hooks/useDebounce'

interface Employee {
  id: number
  firstName: string
  lastName: string
  identificationNumber: string
  identificationType: {
    name: string
  }
}

function empFullName(emp: Employee) {
  return `${emp.firstName} ${emp.lastName}`
}

interface EmployeeSearchProps {
  onSelect?: (employee: Employee | null) => void
  onMultiSelect?: (employees: Employee[]) => void
  multi?: boolean
  placeholder?: string
  className?: string
  label?: string
  error?: string
  defaultValue?: Employee | null
  defaultValues?: Employee[]
}

const DEFAULT_EMPTY_ARRAY: any[] = []

export function EmployeeSearch({
  onSelect,
  onMultiSelect,
  multi = false,
  placeholder = "Buscar empleado por nombre o ID...",
  className = "",
  label,
  error,
  defaultValue = null,
  defaultValues = DEFAULT_EMPTY_ARRAY
}: EmployeeSearchProps) {
  const [query, setQuery] = useState("")
  const [results, setResults] = useState<Employee[]>([])
  const [loading, setLoading] = useState(false)
  const [isOpen, setIsOpen] = useState(false)
  const [selected, setSelected] = useState<Employee | null>(defaultValue)
  const [selectedMulti, setSelectedMulti] = useState<Employee[]>(defaultValues)
  const debouncedQuery = useDebounce(query, 300)
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (defaultValue != null && defaultValue.id !== selected?.id) {
      setSelected(defaultValue)
    }
  }, [defaultValue, selected?.id])

  useEffect(() => {
    if (defaultValues !== undefined) {
      const idsA = defaultValues.map(e => e.id).sort().join(',')
      const idsB = selectedMulti.map(e => e.id).sort().join(',')
      if (idsA !== idsB) {
        setSelectedMulti(defaultValues)
      }
    }
  }, [defaultValues, selectedMulti])

  useEffect(() => {
    const fetchResults = async () => {
      if (debouncedQuery.length < 2) {
        setResults([])
        return
      }

      setLoading(true)
      try {
        const res = await fetch(`/api/employees?search=${encodeURIComponent(debouncedQuery)}&limit=10`)
        const json = await res.json()
        const data = json.data || json || []
        setResults(Array.isArray(data) ? data : [])
      } catch (err) {
        console.error("Error searching employees:", err)
      } finally {
        setLoading(false)
      }
    }

    fetchResults()
  }, [debouncedQuery])

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setIsOpen(false)
      }
    }
    document.addEventListener("mousedown", handleClickOutside)
    return () => document.removeEventListener("mousedown", handleClickOutside)
  }, [])

  const handleSelect = (emp: Employee) => {
    if (multi) {
      if (selectedMulti.some(e => e.id === emp.id)) return
      const newMulti = [...selectedMulti, emp]
      setSelectedMulti(newMulti)
      onMultiSelect?.(newMulti)
      setQuery("")
    } else {
      setSelected(emp)
      onSelect?.(emp)
      setQuery("")
    }
    setResults([])
    setIsOpen(false)
  }

  const handleRemove = (id: number) => {
    const newMulti = selectedMulti.filter(e => e.id !== id)
    setSelectedMulti(newMulti)
    onMultiSelect?.(newMulti)
  }

  const handleClear = () => {
    setSelected(null)
    onSelect?.(null)
    setQuery("")
  }

  return (
    <div ref={containerRef} className={`relative ${className}`}>
      {label && (
        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">
          {label}
        </label>
      )}

      {!multi && selected ? (
        <div className="flex items-center justify-between gap-3 px-4 py-2 bg-blue-50 border border-blue-200 rounded-[var(--radius-lg)] animate-in fade-in zoom-in duration-200">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 rounded-full bg-[var(--color-nc-blue)] text-white flex items-center justify-center text-[10px] font-bold">
                {(selected.firstName[0] + selected.lastName[0]).toUpperCase()}
             </div>
             <div>
                <p className="text-sm font-bold text-blue-900 leading-none">{empFullName(selected)}</p>
                <p className="text-[10px] text-blue-700 font-mono mt-1">ID: {selected.identificationNumber}</p>
             </div>
          </div>
          <button
            type="button"
            onClick={handleClear}
            className="w-6 h-6 flex items-center justify-center rounded-full hover:bg-blue-100 text-blue-600 transition"
          >
            ×
          </button>
        </div>
      ) : (
        <div className="relative">
          <div className={`flex flex-wrap gap-2 p-1 border rounded-[var(--radius-lg)] bg-white transition-all focus-within:ring-2 focus-within:ring-[var(--color-primary)]/25 focus-within:border-[var(--color-primary)] ${error ? 'border-red-500' : 'border-gray-200'}`}>
            {multi && selectedMulti.map(emp => (
