export function useAttendance(token: string | null) {
  const [registries, setRegistries] = useState<AttendanceRegistry[]>([])
  const [employees, setEmployees] = useState<AttendanceEmployee[]>([])
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(0)
  const [pageSize, setPageSize] = useState(DEFAULT_LIMIT)
  const [loading, setLoading] = useState(false)

  const [dateFilter, setDateFilter] = useState("")
  const [employeeFilter, setEmployeeFilter] = useState("")
  const [statusFilter, setStatusFilter] = useState("")

  // Reset page when filters change
  useEffect(() => {
    setPage(0)
  }, [dateFilter, employeeFilter, statusFilter])

  const fetchAttendance = useCallback(async () => {
    if (!token) return
    setLoading(true)
    try {
      const params = new URLSearchParams({
        page: String(page + 1),
        limit: String(pageSize),
        ...(dateFilter && { date: dateFilter }),
        ...(employeeFilter && { employeeId: employeeFilter }),
        ...(statusFilter && { status: statusFilter }),
      })

      const auth = { Authorization: `Bearer ${token}` }
      const [res, empRes] = await Promise.all([
        fetch(`/api/attendance?${params}`, { headers: auth }),
        fetch("/api/employees?limit=100", { headers: auth }),
      ])

      const data = await res.json()
      const empsData = await empRes.json()

      const emps = Array.isArray(empsData) ? empsData : (empsData.data ?? [])
      setEmployees(emps)

      const list = (data.data ?? []).map((r: AttendanceRegistry) => ({
        ...r,
        employee: emps.find((e: AttendanceEmployee) => e.id === r.employeeId),
      }))

      setRegistries(list)
      setTotal(data.total ?? 0)
    } catch (err) {
      console.error("Error fetching attendance:", err)
    } finally {
      setLoading(false)
    }
  }, [token, page, pageSize, dateFilter, employeeFilter, statusFilter])

  useEffect(() => { fetchAttendance() }, [fetchAttendance])

  const handleCloseJourney = async (id: number) => {
    if (!token) return
    if (!confirm("¿Seguro que deseas cerrar esta jornada manualmente?")) return
    try {
      const res = await fetch(`/api/attendance/force-close?id=${id}`, {
        method: "POST",
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        fetchAttendance()
      } else {
        const err = await res.json()
        alert(err.message || "Error al cerrar jornada")
      }
    } catch (err) {
      alert("Error de conexión")
    }
  }

  return {
    registries, total, page, setPage, pageSize, setPageSize, loading,
    dateFilter, setDateFilter, employeeFilter, setEmployeeFilter, statusFilter, setStatusFilter,
    fetchAttendance, handleCloseJourney
  }
}

import { useState, useCallback, useEffect } from 'react'
import { Country, Rate, Location, ConfigEntry, CONFIG_LABELS, FLAT_RATE_KEYS, CONTRACT_CONFIG_KEYS } from '@/types/admin/config'

export function useConfig(token: string | null) {
  const authHeader = {
    Authorization: `Bearer ${token ?? ''}`,
    'Content-Type': 'application/json',
  }

  const [providers,        setProviders]        = useState<{ id: number; name: string }[]>([])
  const [countries,        setCountries]        = useState<Country[]>([])
  const [ratesByCountry,   setRatesByCountry]   = useState<Record<string, Rate[]>>({})
  const [locsByCountry,    setLocsByCountry]    = useState<Record<string, Location[]>>({})
  const [flatByCountry,    setFlatByCountry]    = useState<Record<string, { enabled: boolean; price: string }>>({})
  const [newRateByCountry, setNewRateByCountry] = useState<Record<string, { destId: string; price: string }>>({})
  const [configs,          setConfigs]          = useState<ConfigEntry[]>([])
  const [loading,          setLoading]          = useState(true)
  const [ratesLoading,     setRatesLoading]     = useState(false)
  const [saving,           setSaving]           = useState<string | null>(null)
  const [providerId,       setProviderId]       = useState<number | null>(null)
  const [contractCfg,      setContractCfg]      = useState<Record<string, string>>({})
  const [savingCfgKey,     setSavingCfgKey]     = useState<string | null>(null)

  const loadRates = useCallback(async (pid: number, countryList: Country[]) => {
    setRatesLoading(true)
    try {
      const [rateRes, ...locResponses] = await Promise.all([
        fetch(`/api/shipping-providers/${pid}/rates`, { headers: authHeader }).then(r => r.json()),
        ...countryList.map(c => fetch(`/api/locations?country=${c.code}`, { headers: authHeader }).then(r => r.json())),
      ])

      const all: Rate[] = rateRes.data ?? []
      const byCountry: Record<string, Rate[]> = {}
      for (const c of countryList) byCountry[c.code] = all.filter(r => r.destination.country === c.code)
      setRatesByCountry(byCountry)

      const byLoc: Record<string, Location[]> = {}
      countryList.forEach((c, i) => {
        const rateDestIds = new Set(byCountry[c.code].map(r => r.destination.id))
        byLoc[c.code] = (locResponses[i].data ?? []).filter((l: Location) => !rateDestIds.has(l.id))
      })
      setLocsByCountry(byLoc)

      const newRateInit: Record<string, { destId: string; price: string }> = {}
      for (const c of countryList) newRateInit[c.code] = { destId: '', price: '' }
      setNewRateByCountry(newRateInit)
    } finally {
      setRatesLoading(false)
    }
  }, [token])

  const load = useCallback(async () => {
    setLoading(true)
    try {
      const [provRes, cfgRes, countryRes] = await Promise.all([
        fetch('/api/shipping-providers', { headers: authHeader }).then(r => r.json()),
        fetch('/api/system-config').then(r => r.json()),
        fetch('/api/locations', { headers: authHeader }).then(r => r.json()),
      ])

      const provList: { id: number; name: string }[] = provRes.data ?? []
      setProviders(provList)
      const pid: number | null = provList[0]?.id ?? null
      setProviderId(pid)

      const allCountries: Country[] = (countryRes.data ?? []).filter((c: Country & { code: string | null }) => c.code)
      setCountries(allCountries)

      const cfgMap: Record<string, unknown> = {}
      for (const { key, value } of cfgRes.data ?? []) cfgMap[key] = value

      const flatInit: Record<string, { enabled: boolean; price: string }> = {}
      for (const c of allCountries) {
        const k = c.code.toLowerCase()
        flatInit[c.code] = {
          enabled: Boolean(cfgMap[`${k}_flat_rate_enabled`]),
          price: String(cfgMap[`${k}_flat_rate_price`] ?? '0'),
        }
      }
      setFlatByCountry(flatInit)

      const globals = (cfgRes.data ?? []).filter(
        (e: ConfigEntry) => CONFIG_LABELS[e.key as string] && !FLAT_RATE_KEYS.has(e.key as string),
      )
      setConfigs(globals)

      const contractKeys = new Set(CONTRACT_CONFIG_KEYS.map(c => c.key))
      const contractMap: Record<string, string> = {}
      for (const { key, value } of cfgRes.data ?? []) {
        if (contractKeys.has(key as string)) contractMap[key as string] = String(value)
      }
      setContractCfg(contractMap)

      if (pid) await loadRates(pid, allCountries)
    } finally {
      setLoading(false)
    }
  }, [token])

  useEffect(() => { load() }, [load])

  const patchConfig = async (key: string, value: unknown) => {
    await fetch(`/api/system-config/${key}`, {
      method: 'PATCH',
      headers: authHeader,
      body: JSON.stringify({ value }),
    })
  }

  const saveFlatRate = async (countryCode: string) => {
    const flat = flatByCountry[countryCode]
    if (!flat) return
    const k = countryCode.toLowerCase()
    setSaving(`flat-${countryCode}`)
    try {
      await patchConfig(`${k}_flat_rate_enabled`, flat.enabled)
      await patchConfig(`${k}_flat_rate_price`, Number(flat.price))
      alert(`Tarifa plana ${countryCode} guardada`)
    } catch { alert('Error al guardar') }
    finally { setSaving(null) }
  }

  const saveRate = async (rateId: number, price: number) => {
    if (!providerId) return
    await fetch(`/api/shipping-providers/${providerId}/rates/${rateId}`, {
      method: 'PATCH',
      headers: authHeader,
      body: JSON.stringify({ basePrice: price }),
    })
  }

  const saveLocation = async (locationId: number, name: string) => {
    await fetch(`/api/locations/${locationId}`, {
      method: 'PATCH',
      headers: authHeader,
      body: JSON.stringify({ name }),
    })
    if (providerId) await loadRates(providerId, countries)
  }

  const deleteRate = async (rateId: number) => {
    if (!providerId || !confirm('¿Eliminar esta tarifa?')) return
    await fetch(`/api/shipping-providers/${providerId}/rates/${rateId}`, {
      method: 'DELETE',
      headers: authHeader,
    })
    loadRates(providerId, countries)
  }

  const addRate = async (countryCode: string) => {
    if (!providerId) return
    const nr = newRateByCountry[countryCode]
    if (!nr?.destId || !nr?.price) return
    setSaving(`add-${countryCode}`)
    try {
      await fetch(`/api/shipping-providers/${providerId}/rates`, {
        method: 'POST',
        headers: authHeader,
        body: JSON.stringify({ destinationId: Number(nr.destId), basePrice: Number(nr.price), countryCode }),
      })
      loadRates(providerId, countries)
    } finally { setSaving(null) }
  }

  const saveConfig = async (key: string, value: unknown) => {
    setSaving(`cfg-${key}`)
    try {
      await patchConfig(key, Number(value))
      alert(`${CONFIG_LABELS[key] ?? key} guardado`)
    } catch { alert('Error al guardar') }
    finally { setSaving(null) }
  }

  const saveContractCfg = async (key: string) => {
    const val = contractCfg[key]
    if (val === undefined || val === '') return
    setSavingCfgKey(key)
    try {
      await patchConfig(key, Number(val))
      alert('Guardado correctamente')
    } catch { alert('Error al guardar') }
    finally { setSavingCfgKey(null) }
  }

  return {
    providers, countries, ratesByCountry, locsByCountry, flatByCountry, setFlatByCountry,
    newRateByCountry, setNewRateByCountry, configs, loading, ratesLoading, saving,
    providerId, setProviderId, contractCfg, setContractCfg, savingCfgKey,
    load, loadRates, saveFlatRate, saveRate, saveLocation, deleteRate, addRate, saveConfig, saveContractCfg
  }
}

import { useState, useCallback, useEffect } from 'react'
import { Contract } from '@/types/admin/contracts'
import { contractsClient } from '@/lib/api-client/contracts'

const DEFAULT_LIMIT = 10

export function useContracts() {
  const [contracts, setContracts] = useState<Contract[]>([])
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(0)
  const [search, setSearch] = useState('')
  const [pageSize, setPageSize] = useState(DEFAULT_LIMIT)
  const [loading, setLoading] = useState(false)

  const [dirty, setDirty] = useState<Record<number, { isActive: boolean }>>({})
  const [selected, setSelected] = useState<Set<number>>(new Set())
  const [saving, setSaving] = useState<Set<number>>(new Set())

  const [historyOpen, setHistoryOpen] = useState(false)
  const [historyList, setHistoryList] = useState<Contract[]>([])
  const [historyLoading, setHistoryLoading] = useState(false)
  const [historyEmpName, setHistoryEmpName] = useState('')

  const fetchContracts = useCallback(async () => {
    setLoading(true)
    setDirty({})
    setSelected(new Set())
    try {
      const data = await contractsClient.getContracts(page, pageSize, search)
      setContracts(data.data ?? [])
      setTotal(data.total ?? 0)
    } catch (e) { console.error(e) } finally { setLoading(false) }
  }, [page, pageSize, search])

  useEffect(() => { fetchContracts() }, [fetchContracts])

  const toggleActive = (id: number, current: boolean) => {
    setDirty(d => ({ ...d, [id]: { ...(d[id] ?? {}), isActive: !(d[id]?.isActive ?? current) } }))
  }

  const saveRow = async (id: number) => {
    const changes = dirty[id]
    if (!changes) return
    setSaving(s => new Set(s).add(id))
    try {
      await contractsClient.updateContract(id, changes)
      setDirty(d => { const n = { ...d }; delete n[id]; return n })
      setContracts(list => list.map(c => c.id === id ? { ...c, ...changes } : c))
    } finally { setSaving(s => { const n = new Set(s); n.delete(id); return n }) }
  }

  const saveAll = async () => { await Promise.all(Object.keys(dirty).map(id => saveRow(Number(id)))) }

  const openHistory = async (empId: number, empName: string) => {
    setHistoryOpen(true); setHistoryEmpName(empName); setHistoryLoading(true); setHistoryList([])
    try {
      const data = await contractsClient.getEmployeeContractsHistory(empId)
      setHistoryList(Array.isArray(data) ? data : (data.data ?? []))
    } catch { alert('Error') } finally { setHistoryLoading(false) }
  }

  return {
    contracts, total, page, setPage, search, setSearch, pageSize, setPageSize, loading,
    dirty, setDirty, selected, setSelected, saving, historyOpen, setHistoryOpen, historyList, historyLoading, historyEmpName,
    fetchContracts, toggleActive, saveRow, saveAll, openHistory
  }
}

import { useState, useCallback, useEffect } from 'react'
import { useAuth } from '@/context/AuthContext'

export type DashboardEmployee = {
  id: number
  name: string
  email: string
  status: 'ACTIVE' | 'INACTIVE'
  roles: string[]
  activeContract: { id: number; job: { title: string } } | null
}

export type WorkloadEntry = {
  employeeId: number
  employeeName: string
  totalTasks: number
  pendingCount: number
  inProgressCount: number
  completedCount: number
  notDoneCount: number
}

const PIE_COLORS = [
  { name: 'Pendientes',   key: 'pendingCount',    color: '#facc15' },
  { name: 'En Proceso',   key: 'inProgressCount', color: '#3b82f6' },
  { name: 'Completadas',  key: 'completedCount',  color: '#22c55e' },
  { name: 'No Hechas',    key: 'notDoneCount',    color: '#ef4444' },
]

export function useDashboard() {
  const { token } = useAuth()
  const [activeCount, setActiveCount] = useState<number | null>(null)
  const [inProgressTasks, setInProgressTasks] = useState<number | null>(null)
  const [todayAttendances, setTodayAttendances] = useState<number | null>(null)
  const [totalQuotations, setTotalQuotations] = useState<number | null>(null)
  const [recentEmployees, setRecentEmployees] = useState<DashboardEmployee[]>([])
  const [pieData, setPieData] = useState<{ name: string; value: number; color: string }[]>([])

  const fetchAll = useCallback(async () => {
    if (!token) return
    const auth = { Authorization: `Bearer ${token}` }

    const [empRes, workloadRes, attendanceRes, quotationsRes] = await Promise.allSettled([
      fetch('/api/employees?status=ACTIVE&limit=1', { headers: auth }).then(r => r.json()),
      fetch('/api/analytics/workload', { headers: auth }).then(r => r.json()),
      fetch('/api/attendance?page=1&pageSize=1', { headers: auth }).then(r => r.json()),
      fetch('/api/quotations?page=1&limit=1', { headers: auth }).then(r => r.json()),
    ])

    if (empRes.status === 'fulfilled') setActiveCount(empRes.value.total ?? 0)
    if (workloadRes.status === 'fulfilled' && Array.isArray(workloadRes.value)) {
      const rows = workloadRes.value as WorkloadEntry[]
      setInProgressTasks(rows.reduce((acc, e) => acc + e.inProgressCount, 0))
      const totals = PIE_COLORS.map(c => ({
        name: c.name,
        color: c.color,
        value: rows.reduce((acc, e) => acc + (e[c.key as keyof WorkloadEntry] as number), 0),
      })).filter(d => d.value > 0)
      setPieData(totals)
    }
    if (attendanceRes.status === 'fulfilled') setTodayAttendances(attendanceRes.value.total ?? 0)
    if (quotationsRes.status === 'fulfilled') setTotalQuotations(quotationsRes.value.total ?? 0)

    try {
      const empList = await fetch('/api/employees?page=1&limit=4', { headers: auth }).then(r => r.json())
      setRecentEmployees(empList.data ?? [])
    } catch { /* silent */ }
  }, [token])

  useEffect(() => { fetchAll() }, [fetchAll])

  return {
    activeCount, inProgressTasks, todayAttendances, totalQuotations,
    recentEmployees, pieData, fetchAll
  }
}

import { useState, useCallback, useEffect } from 'react'
import { Employee, Role, Job, ContractType, IdentificationType } from '@/types/admin/employees'

const DEFAULT_LIMIT = 10

export function useEmployees() {
  const [employees, setEmployees] = useState<Employee[]>([])
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(0)
  const [search, setSearch] = useState('')
  const [pageSize, setPageSize] = useState(DEFAULT_LIMIT)
  const [loading, setLoading] = useState(false)
  const [filterStatus, setFilterStatus] = useState<string>('')
  const [filterRole, setFilterRole] = useState<string>('')

  // Dirty rows: pending status changes not yet saved
  const [dirty, setDirty] = useState<Record<number, 'ACTIVE' | 'INACTIVE'>>({})
  const [selected, setSelected] = useState<Set<number>>(new Set())
  const [saving, setSaving] = useState<Set<number>>(new Set())

  // Dependencies
  const [roles, setRoles] = useState<Role[]>([])
  const [jobs, setJobs] = useState<Job[]>([])
  const [contractTypes, setContractTypes] = useState<ContractType[]>([])
  const [identificationTypes, setIdentificationTypes] = useState<IdentificationType[]>([])

  const fetchEmployees = useCallback(async () => {
    setLoading(true)
    setDirty({})
    setSelected(new Set())
    try {
      const params = new URLSearchParams({
        page: String(page + 1),
        limit: String(pageSize),
        ...(search && { search }),
        ...(filterStatus && { status: filterStatus }),
        ...(filterRole && { roleId: filterRole }),
      })
      const res = await fetch(`/api/employees?${params}`)
      const data = await res.json()
      setEmployees(data.data ?? [])
      setTotal(data.total ?? 0)
    } finally {
      setLoading(false)
    }
  }, [page, pageSize, search, filterStatus, filterRole])

  useEffect(() => { fetchEmployees() }, [fetchEmployees])

  useEffect(() => {
    Promise.all([
      fetch('/api/roles').then(x => x.json()),
      fetch('/api/jobs').then(x => x.json()),
      fetch('/api/contract-types').then(x => x.json()),
      fetch('/api/identification-types').then(x => x.json()),
    ]).then(([r, j, ct, it]) => {
      setRoles(r)
      setJobs(j)
      setContractTypes(ct)
      setIdentificationTypes(it)
    }).catch(err => console.error('Error fetching dependencies:', err))
  }, [])

  const toggleStatus = (id: number, current: 'ACTIVE' | 'INACTIVE') => {
    const currentStatus = dirty[id] ?? current
    setDirty(d => ({ ...d, [id]: currentStatus === 'ACTIVE' ? 'INACTIVE' : 'ACTIVE' }))
  }

  const saveRow = async (id: number) => {
    const status = dirty[id]
    if (!status) return
    setSaving(s => new Set(s).add(id))
    try {
      await fetch(`/api/employees?id=${id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status }),
      })
      setDirty(d => { const n = { ...d }; delete n[id]; return n })
      setEmployees(list => list.map(e => e.id === id ? { ...e, status } : e))
    } finally {
      setSaving(s => { const n = new Set(s); n.delete(id); return n })
    }
  }

  const saveAll = async () => {
    await Promise.all(Object.keys(dirty).map(id => saveRow(Number(id))))
  }

  const bulkUpdate = async (status: 'ACTIVE' | 'INACTIVE') => {
    await Promise.all(
      [...selected].map(id =>
        fetch(`/api/employees?id=${id}`, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ status }),
        })
      )
    )
    setSelected(new Set())
    fetchEmployees()
  }

  const toggleSelect = (id: number) => {
    setSelected(s => {
      const n = new Set(s)
      n.has(id) ? n.delete(id) : n.add(id)
      return n
    })
  }

  const toggleSelectAll = () => {
    if (selected.size === employees.length) {
      setSelected(new Set())
    } else {
      setSelected(new Set(employees.map(e => e.id)))
    }
  }

  return {
    employees, total, page, setPage, search, setSearch, pageSize, setPageSize,
    loading, filterStatus, setFilterStatus, filterRole, setFilterRole,
    dirty, setDirty, selected, setSelected, saving, setSaving,
    roles, jobs, contractTypes, identificationTypes,
    fetchEmployees, toggleStatus, saveRow, saveAll, bulkUpdate, toggleSelect, toggleSelectAll
  }
}

import { useState, useCallback, useEffect } from 'react'
import { Job } from '@/types/admin/jobs'

const DEFAULT_LIMIT = 10

export function useJobs() {
  const [jobs, setJobs] = useState<Job[]>([])
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(0)
  const [pageSize, setPageSize] = useState(DEFAULT_LIMIT)
  const [loading, setLoading] = useState(false)

  const fetchJobs = useCallback(async () => {
    setLoading(true)
    try {
      const params = new URLSearchParams({ page: String(page + 1), limit: String(pageSize) })
      const res = await fetch(`/api/jobs?${params}`)
      const data = await res.json()
      setJobs(data.data ?? [])
      setTotal(data.total ?? 0)
    } catch (err) { console.error(err) } finally { setLoading(false) }
  }, [page, pageSize])

  useEffect(() => { fetchJobs() }, [fetchJobs])

  const deleteJob = async (id: number) => {
    if (!confirm('¿Eliminar?')) return
    try {
      const res = await fetch(`/api/jobs?id=${id}`, { method: 'DELETE' })
      if (res.ok) fetchJobs()
    } catch { alert('Error') }
  }

  return { jobs, total, page, setPage, pageSize, setPageSize, loading, fetchJobs, deleteJob }
}

import { useState, useCallback, useEffect } from 'react'
import { CotizacionRecord, Office, QuotationTab } from '@/types/admin/quotations'

const LIMIT = 10

export function useQuotations(token: string | null) {
  const [tab, setTab] = useState<QuotationTab>('publica')

  // Publica
  const [pubRecords, setPubRecords] = useState<CotizacionRecord[]>([])
  const [pubTotal, setPubTotal] = useState(0)
  const [pubPage, setPubPage] = useState(0)
  const [pubPageSize, setPubPageSize] = useState(LIMIT)
  const [pubLoading, setPubLoading] = useState(false)

  // Empleados
  const [empRecords, setEmpRecords] = useState<CotizacionRecord[]>([])
  const [empTotal, setEmpTotal] = useState(0)
  const [empPage, setEmpPage] = useState(0)
  const [empPageSize, setEmpPageSize] = useState(LIMIT)
  const [empLoading, setEmpLoading] = useState(false)

  // Offices
  const [offices, setOffices] = useState<Office[]>([])
  const [loadingO, setLoadingO] = useState(false)

  const fetchPublica = useCallback(async () => {
    setPubLoading(true)
    try {
      const res = await fetch(`/api/cotizacion-records?source=PUBLIC&page=${pubPage + 1}&pageSize=${pubPageSize}`)
      const data = await res.json()
      setPubRecords(data.data ?? [])
      setPubTotal(data.total ?? 0)
    } catch { } finally { setPubLoading(false) }
  }, [pubPage, pubPageSize])

  const fetchEmpleados = useCallback(async () => {
    setEmpLoading(true)
    try {
      const res = await fetch(`/api/cotizacion-records?source=EMPLOYEE&page=${empPage + 1}&pageSize=${empPageSize}`)
      const data = await res.json()
      setEmpRecords(data.data ?? [])
      setEmpTotal(data.total ?? 0)
    } catch { } finally { setEmpLoading(false) }
  }, [empPage, empPageSize])

  const fetchOffices = useCallback(async () => {
    setLoadingO(true)
    try {
      const res = await fetch('/api/pickup-points')
      const data = await res.json()
      setOffices(data.data ?? [])
    } catch { } finally { setLoadingO(false) }
  }, [])

  useEffect(() => { if (tab === 'publica') fetchPublica() }, [tab, fetchPublica])
  useEffect(() => { if (tab === 'empleados') fetchEmpleados() }, [tab, fetchEmpleados])
  useEffect(() => { if (tab === 'offices') fetchOffices() }, [tab, fetchOffices])

  return {
    tab, setTab,
    pubRecords, pubTotal, pubPage, setPubPage, pubPageSize, setPubPageSize, pubLoading,
    empRecords, empTotal, empPage, setEmpPage, empPageSize, setEmpPageSize, empLoading,
    offices, loadingO, fetchPublica, fetchEmpleados, fetchOffices
  }
}

import { useState, useCallback, useEffect, useMemo } from 'react'
import { KPIRecord, Range, Metrics, TimePoint, EmployeeRow } from '@/types/admin/employee-reports'

function avg(values: (number | null)[]): number | null {
  const clean = values.filter((v): v is number => v != null)
  return clean.length > 0 ? clean.reduce((s, v) => s + v, 0) / clean.length : null
}
function sum(values: (number | null)[]): number { return values.reduce((s: number, v) => s + Number(v ?? 0), 0) }
function formatDate(iso: string) { return new Date(iso + 'T12:00:00').toLocaleDateString('es-CO', { month: 'short', day: 'numeric' }) }

export function useEmployeeReports(token: string | null) {
  const [range, setRange] = useState<Range>('all')
  const [employeeFilter, setEmployeeFilter] = useState<number | null>(null)
  const [records, setRecords] = useState<KPIRecord[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const fetchData = useCallback(async () => {
    if (!token) return
    setLoading(true); setError(null)
    try {
      const params = new URLSearchParams({ range })
      if (employeeFilter) params.set('employeeId', String(employeeFilter))
      const res = await fetch(`/api/employee-kpis?${params}`, { headers: { Authorization: `Bearer ${token}` }, cache: 'no-store' })
      if (!res.ok) throw new Error(`HTTP ${res.status}`)
      const json = await res.json()
      setRecords(json.data ?? json ?? [])
    } catch (e) { setError(e instanceof Error ? e.message : 'Error') } finally { setLoading(false) }
  }, [token, range, employeeFilter])

  useEffect(() => { fetchData() }, [fetchData])

  const uniqueEmployees = useMemo(() => {
    const map = new Map<number, string>()
    records.forEach(r => map.set(r.employeeId, r.employee.name))
    return Array.from(map.entries()).map(([id, name]) => ({ id, name })).sort((a, b) => a.name.localeCompare(b.name))
  }, [records])

  const metrics = useMemo<Metrics>(() => ({
    totalWorkedHours: sum(records.map(r => r.totalWorkedHours)),
    totalTasksCompleted: sum(records.map(r => r.tasksCompleted)),
    avgProductivity: avg(records.map(r => r.productivityScore)),
    avgTaskTime: avg(records.map(r => r.avgTaskTimeMinutes)),
  }), [records])

  const timeSeries = useMemo<TimePoint[]>(() => {
    const byDate = new Map<string, KPIRecord[]>()
    records.forEach(r => { const d = r.date.slice(0, 10); if (!byDate.has(d)) byDate.set(d, []); byDate.get(d)!.push(r) })
    return Array.from(byDate.entries()).sort(([a], [b]) => a.localeCompare(b)).map(([date, rows]) => ({ date: formatDate(date), workedHours: sum(rows.map(r => r.totalWorkedHours)), tasksCompleted: sum(rows.map(r => r.tasksCompleted)), productivityScore: avg(rows.map(r => r.productivityScore)) }))
  }, [records])

  const employeeRows = useMemo<EmployeeRow[]>(() => {
    const byEmp = new Map<number, { name: string; rows: KPIRecord[] }>()
    records.forEach(r => { if (!byEmp.has(r.employeeId)) byEmp.set(r.employeeId, { name: r.employee.name, rows: [] }); byEmp.get(r.employeeId)!.rows.push(r) })
    return Array.from(byEmp.entries()).map(([id, { name, rows }]) => ({ employeeId: id, name, totalWorkedHours: sum(rows.map(r => r.totalWorkedHours)), tasksCompleted: sum(rows.map(r => r.tasksCompleted)), avgTaskTime: avg(rows.map(r => r.avgTaskTimeMinutes)), avgProductivity: avg(rows.map(r => r.productivityScore)) }))
  }, [records])

  return { range, setRange, employeeFilter, setEmployeeFilter, records, loading, error, fetchData, uniqueEmployees, metrics, timeSeries, employeeRows }
}

import { useState, useCallback, useEffect, useMemo } from 'react'
import { Alert, PerformanceEntry, WorkloadEntry, CompletionEntry, Employee, AppliedFilters } from '@/types/admin/reports'

const PERF_LIMIT = 10

function buildBaseParams(f: AppliedFilters) {
  const p = new URLSearchParams()
  if (f.from) {
    const d = new Date(f.from + 'T00:00:00')
    p.set('from', d.toISOString())
  }
  if (f.to) {
    const d = new Date(f.to + 'T23:59:59.999')
    p.set('to', d.toISOString())
  }
  if (f.employeeId) p.set('employeeId', f.employeeId)
  return p
}

export function useReports(token: string | null) {
  const [alerts, setAlerts] = useState<Alert[]>([])
  const [performance, setPerformance] = useState<PerformanceEntry[]>([])
  const [perfTotal, setPerfTotal] = useState(0)
  const [perfPage, setPerfPage] = useState(0)
  const [workload, setWorkload] = useState<WorkloadEntry[]>([])
  const [completion, setCompletion] = useState<CompletionEntry[]>([])
  const [employees, setEmployees] = useState<Employee[]>([])

  const [fromDate, setFromDate] = useState('')
  const [toDate, setToDate] = useState('')
  const [selectedEmployeeId, setSelectedEmployeeId] = useState('')
  const [appliedFilters, setAppliedFilters] = useState<AppliedFilters>({ from: '', to: '', employeeId: '' })

  const [loading, setLoading] = useState({ alerts: true, performance: true, workload: true, completion: true })

  const fetchMain = useCallback(async () => {
    if (!token) return
    setLoading({ alerts: true, performance: true, workload: true, completion: true })

    const auth = { Authorization: `Bearer ${token}` }
    const base = buildBaseParams(appliedFilters)
    const perfQ = new URLSearchParams(base)
    perfQ.set('page', '1')
    perfQ.set('limit', String(PERF_LIMIT))

    const [ar, wr, cr, pr] = await Promise.allSettled([
      fetch(`/api/analytics/alerts?${base}`, { headers: auth }).then(r => r.json()),
      fetch(`/api/analytics/workload?${base}`, { headers: auth }).then(r => r.json()),
      fetch(`/api/analytics/task-completion?${base}`, { headers: auth }).then(r => r.json()),
      fetch(`/api/analytics/employee-performance?${perfQ}`, { headers: auth }).then(r => r.json()),
    ])

    setAlerts(ar.status === 'fulfilled' && Array.isArray(ar.value) ? ar.value : [])
    setWorkload(wr.status === 'fulfilled' && Array.isArray(wr.value) ? wr.value : [])
    setCompletion(cr.status === 'fulfilled' && Array.isArray(cr.value) ? cr.value : [])

    if (pr.status === 'fulfilled') {
      const d = pr.value
      setPerformance(Array.isArray(d) ? d : (d.data ?? []))
      setPerfTotal(Array.isArray(d) ? d.length : (d.total ?? 0))
    }

    setPerfPage(0)
    setLoading({ alerts: false, performance: false, workload: false, completion: false })
  }, [token, appliedFilters])

  useEffect(() => { fetchMain() }, [fetchMain])

  useEffect(() => {
    if (!token) return
    fetch('/api/employees?limit=200', { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.json())
      .then(data => setEmployees(Array.isArray(data) ? data : (data.data ?? [])))
      .catch(() => { })
  }, [token])

  const handlePerfPageChange = useCallback(async (page: number) => {
    if (!token) return
    setPerfPage(page)
    setLoading(l => ({ ...l, performance: true }))
    const auth = { Authorization: `Bearer ${token}` }
    const params = buildBaseParams(appliedFilters)
    params.set('page', String(page + 1))
    params.set('limit', String(PERF_LIMIT))
    try {
      const res = await fetch(`/api/analytics/employee-performance?${params}`, { headers: auth })
      const d = await res.json()
      setPerformance(Array.isArray(d) ? d : (d.data ?? []))
      setPerfTotal(Array.isArray(d) ? d.length : (d.total ?? 0))
    } catch { }
    setLoading(l => ({ ...l, performance: false }))
  }, [token, appliedFilters])

  return {
    alerts, performance, perfTotal, perfPage, workload, completion, employees,
    fromDate, setFromDate, toDate, setToDate, selectedEmployeeId, setSelectedEmployeeId,
    appliedFilters, setAppliedFilters, loading, fetchMain, handlePerfPageChange
  }
}

import { useState, useCallback, useEffect, useRef } from 'react'
import { Locker, Envio } from '@/types/admin/shipments'

const DEFAULT_LIMIT = 10

export function useShipments(token: string | null) {
  const headers = { Authorization: `Bearer ${token ?? ''}` }

  // Lockers
  const [lockers, setLockers] = useState<Locker[]>([])
  const [lockersTotal, setLockersTotal] = useState(0)
  const [lockersPage, setLockersPage] = useState(0)
  const [lockersPageSize, setLockersPageSize] = useState(DEFAULT_LIMIT)
  const [lockersLoading, setLockersLoading] = useState(false)
  const [syncing, setSyncing] = useState(false)
  const [syncTerm, setSyncTerm] = useState('')

  // Envíos
  const [selectedLocker, setSelectedLocker] = useState<Locker | null>(null)
  const [envios, setEnvios] = useState<Envio[]>([])
  const [enviosTotal, setEnviosTotal] = useState(0)
  const [enviosPage, setEnviosPage] = useState(0)
  const [enviosPageSize, setEnviosPageSize] = useState(DEFAULT_LIMIT)
  const [enviosLoading, setEnviosLoading] = useState(false)
  const [envioSearch, setEnvioSearch] = useState('')
  const [debouncedEnvioSearch, setDebouncedEnvioSearch] = useState('')

  const searchRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  useEffect(() => {
    if (searchRef.current) clearTimeout(searchRef.current)
    searchRef.current = setTimeout(() => setDebouncedEnvioSearch(envioSearch), 350)
    return () => { if (searchRef.current) clearTimeout(searchRef.current) }
  }, [envioSearch])

  const loadLockers = useCallback(async () => {
    setLockersLoading(true)
    try {
      const p = new URLSearchParams({ page: String(lockersPage + 1), limit: String(lockersPageSize) })
      const res = await fetch(`/api/lockers?${p}`, { headers })
      const json = await res.json()
      setLockers(json.data ?? [])
      setLockersTotal(json.total ?? 0)
    } catch (e) { console.error(e) } finally { setLockersLoading(false) }
  }, [lockersPage, lockersPageSize, token])

  const loadEnvios = useCallback(async () => {
    if (!selectedLocker) return
    setEnviosLoading(true)
    try {
      const params = new URLSearchParams({ page: String(enviosPage + 1), limit: String(enviosPageSize) })
      if (debouncedEnvioSearch) params.set('search', debouncedEnvioSearch)
      const res = await fetch(`/api/lockers/${selectedLocker.id}/shipments?${params}`, { headers })
      const json = await res.json()
      setEnvios(json.data ?? [])
      setEnviosTotal(json.total ?? 0)
    } catch (e) { console.error(e) } finally { setEnviosLoading(false) }
  }, [selectedLocker, debouncedEnvioSearch, enviosPage, enviosPageSize, token])

  useEffect(() => { loadLockers() }, [loadLockers])
  useEffect(() => { loadEnvios() }, [loadEnvios])

  const handleSync = async () => {
    setSyncing(true)
    try {
      const res = await fetch('/api/odoo/sync-lockers', {
        method: 'POST',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({ searchTerm: syncTerm.trim() || undefined }),
      })
      if (res.ok) { loadLockers(); if (selectedLocker) loadEnvios() }
    } finally { setSyncing(false) }
  }

  return {
    lockers, lockersTotal, lockersPage, setLockersPage, lockersPageSize, setLockersPageSize, lockersLoading,
    syncing, syncTerm, setSyncTerm, handleSync,
    selectedLocker, setSelectedLocker, envios, enviosTotal, enviosPage, setEnviosPage, enviosPageSize, setEnviosPageSize, enviosLoading,
    envioSearch, setEnvioSearch, loadLockers, loadEnvios
  }
}

import { useState, useCallback, useEffect } from 'react'
import { Task, TaskStatus, TaskEmployee } from '@/types/admin/tasks'

const DEFAULT_LIMIT = 10

export function useTasks(token: string | null) {
  const [tasks, setTasks] = useState<Task[]>([])
  const [employees, setEmployees] = useState<TaskEmployee[]>([])
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(0)
  const [pageSize, setPageSize] = useState(DEFAULT_LIMIT)
  const [loading, setLoading] = useState(false)
  const [statusFilter, setStatusFilter] = useState<TaskStatus | ''>('')
  const [employeeFilter, setEmployeeFilter] = useState<string>('')

  const fetchData = useCallback(async () => {
    if (!token) return
    setLoading(true)
    const auth = { Authorization: `Bearer ${token}` }
    try {
      const taskParams = new URLSearchParams({
        page: String(page + 1),
        limit: String(pageSize),
        ...(statusFilter && { status: statusFilter }),
        ...(employeeFilter && { employeeId: employeeFilter }),
      })

      const [tasksRes, empsRes] = await Promise.all([
        fetch(`/api/tasks?${taskParams}`, { headers: auth }),
        fetch('/api/employees?limit=100', { headers: auth }),
      ])

      const tasksData = await tasksRes.json()
      const empsData = await empsRes.json()

      const emps = Array.isArray(empsData) ? empsData : (empsData.data ?? [])
      setEmployees(emps)

      const tasksWithEmps = (tasksData.data ?? []).map((t: Task) => ({
        ...t,
        employee: emps.find((e: TaskEmployee) => e.id === t.employeeId)
      }))

      setTasks(tasksWithEmps)
      setTotal(tasksData.total ?? 0)
    } catch (err) {
      console.error('Error fetching tasks:', err)
    } finally {
      setLoading(false)
    }
  }, [page, pageSize, statusFilter, employeeFilter, token])

  useEffect(() => { fetchData() }, [fetchData])

  const handleDeleteTask = async (id: number) => {
    if (!confirm('¿Deseas eliminar esta tarea permanentemente?') || !token) return
    try {
      const res = await fetch(`/api/tasks?id=${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) fetchData()
    } catch {
      alert('Error al eliminar tarea')
    }
  }

  const handleCheckOverdue = async () => {
    if (!confirm('¿Deseas marcar todas las tareas pendientes vencidas como "No Hechas"?')) return
    try {
      const res = await fetch('/api/tasks/check-overdue', { method: 'POST' })
      if (res.ok) {
        alert('Tareas procesadas correctamente')
        fetchData()
      }
    } catch (err) {
      alert('Error al verificar tareas vencidas')
    }
  }

  return {
    tasks, employees, total, page, setPage, pageSize, setPageSize, loading,
    statusFilter, setStatusFilter, employeeFilter, setEmployeeFilter,
    fetchData, handleDeleteTask, handleCheckOverdue
  }
}

export const jornadaClient = {
  async getToday(token: string) {
    const res = await fetch(`/api/attendance/today?_=${Date.now()}`, {
      headers: { Authorization: `Bearer ${token}` },
      cache: 'no-store',
    })
    if (!res.ok) {
      if (res.status === 401) throw new Error('Sesión expirada, inicia sesión nuevamente.')
      throw new Error('No se pudo cargar la jornada.')
    }
    return res.json()
  },

  async action(token: string, path: string) {
    const res = await fetch(path, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`
      },
      cache: 'no-store',
    })

    if (!res.ok) {
      const data = await res.json().catch(() => null)
      const msg = (data && typeof data === 'object' && 'message' in data ? (data as { message: string }).message : '') || 'Error en la operación'
      throw new Error(msg)
    }
    return res.json()
  },

  async loadTasks(token: string, employeeId: number) {
    const [pendingRes, inProgressRes] = await Promise.all([
      fetch(`/api/tasks?employeeId=${employeeId}&status=PENDING&limit=50`, { headers: { Authorization: `Bearer ${token}` } }),
      fetch(`/api/tasks?employeeId=${employeeId}&status=IN_PROGRESS&limit=50`, { headers: { Authorization: `Bearer ${token}` } }),
    ])
    const [pending, inProgress] = await Promise.all([
      pendingRes.ok ? pendingRes.json() : { data: [] },
      inProgressRes.ok ? inProgressRes.json() : { data: [] },
    ])
    return [
      ...(pending.data ?? pending ?? []),
      ...(inProgress.data ?? inProgress ?? []),
    ].map((t: any) => ({ id: t.id, title: t.title, status: t.status }))
  },

  async completeTask(token: string, taskId: number) {
    const res = await fetch(`/api/tasks?id=${taskId}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${token}`
      },
      body: JSON.stringify({ status: 'COMPLETED', endTime: new Date() }),
    })
    if (!res.ok) throw new Error('Error al completar tarea')
    return res.json()
  }
}

import { Office } from '@/types/admin/quotations';

export const pickupPointsClient = {
  async saveOffice(token: string | null, form: any, editingOfficeId?: number) {
    const url = editingOfficeId ? `/api/pickup-points?id=${editingOfficeId}` : '/api/pickup-points';
    const method = editingOfficeId ? 'PATCH' : 'POST';

    const res = await fetch(url, {
      method,
      headers: { 
        'Content-Type': 'application/json',
        ...(token ? { Authorization: `Bearer ${token}` } : {})
      },
      body: JSON.stringify({
        ...form,
        latitude: parseFloat(form.latitude),
        longitude: parseFloat(form.longitude),
        coverageRadiusMiles: form.coverageRadiusMiles ? parseFloat(form.coverageRadiusMiles) : null
      })
    });

    if (!res.ok) {
      throw new Error('Error saving office');
    }
    return res.json();
  },

  async toggleActive(token: string | null, id: number, currentStatus: boolean) {
    const res = await fetch(`/api/pickup-points?id=${id}`, {
      method: 'PATCH',
      headers: { 
        'Content-Type': 'application/json',
        ...(token ? { Authorization: `Bearer ${token}` } : {})
      },
      body: JSON.stringify({ isActive: !currentStatus })
    });

    if (!res.ok) {
      throw new Error('Error toggling office status');
    }
    return res.json();
  },

  async deleteOffice(token: string | null, id: number) {
    const res = await fetch(`/api/pickup-points?id=${id}`, {
      method: 'DELETE',
      headers: {
        ...(token ? { Authorization: `Bearer ${token}` } : {})
      }
    });

    if (!res.ok) {
      throw new Error('Error deleting office');
    }
    return res.json();
  }
};

import { useState, useCallback } from 'react'
import { useAuth } from '@/context/AuthContext'
import { useOdooSearch } from '@/hooks/useOdooSearch'
import { useOdooSubmit } from '@/hooks/useOdooSubmit'
import { useCitiesAndOffices } from '@/hooks/useCitiesAndOffices'
import { useCotizacionesForm } from '@/hooks/useCotizacionesForm'
import { useCotizacionesCalc } from '@/hooks/useCotizacionesCalc'

export function useCotizaciones() {
  const { user } = useAuth()

  const form = useCotizacionesForm()
  const data = useCitiesAndOffices(form.country, form.dept)
  const calc = useCotizacionesCalc(form.parse)

  const odooSearch = useOdooSearch()
  const odooSubmit = useOdooSubmit()

  const [isOdooModalOpen, setIsOdooModalOpen] = useState(false)
  const [selectedCustomer, setSelectedCustomer] = useState<any | null>(null)

  const handleCalc = useCallback(async () => {
    if (!form.isValid(data.flatRate.enabled)) {
      calc.setError('Completa peso, dimensiones, valor declarado' + (!data.flatRate.enabled ? ' y ciudad' : ''))
      return
    }
    await calc.calculate({
      country: form.country, weight: form.weight, dims: form.dims, valor: form.valor,
      millas: form.millas, cityId: form.cityId, flatRateEnabled: data.flatRate.enabled, employeeId: user?.id
    })
  }, [form, data.flatRate.enabled, calc, user])

  const handleSendToOdoo = useCallback(async () => {
    if (!selectedCustomer || !calc.result) return
    const success = await odooSubmit.sendToOdoo({
      customerId: selectedCustomer.id, result: calc.result, country: form.country, quotationId: calc.quotationId
    })
    if (success) {
      setTimeout(() => {
        setIsOdooModalOpen(false)
        odooSubmit.setSuccess('')
        setSelectedCustomer(null)
        odooSearch.setQuery('')
      }, 2500)
    }
  }, [selectedCustomer, calc.result, calc.quotationId, form.country, odooSubmit, odooSearch])

  return {
    ...form, ...data, ...calc, handleCalc,
    // Odoo
    isOdooModalOpen, setIsOdooModalOpen,
    odooSearchQuery: odooSearch.query, setOdooSearchQuery: odooSearch.setQuery,
    isSearchingOdoo: odooSearch.isSearching, odooCustomers: odooSearch.customers,
    selectedCustomer, setSelectedCustomer,
    isSendingToOdoo: odooSubmit.isSending, odooError: odooSearch.error || odooSubmit.error,
    odooSuccess: odooSubmit.success, handleSendToOdoo
  }
}

import { useState, useEffect, useCallback, useRef } from 'react'
import { useAuth } from '@/context/AuthContext'
import { Shipment, RowFeedback } from './types'

const DEFAULT_LIMIT = 10

export function useEnvios() {
  const { token } = useAuth()
  const authToken = token ?? ''

  const [shipments, setShipments] = useState<Shipment[]>([])
  const [total, setTotal] = useState(0)
  const [page, setPage] = useState(0)
  const [pageSize, setPageSize] = useState(DEFAULT_LIMIT)
  const [loading, setLoading] = useState(false)

  const [search, setSearch] = useState('')
  const [debouncedSearch, setDebouncedSearch] = useState('')

  // Per-row tracking edit state
  const [editingId, setEditingId] = useState<number | null>(null)
  const [editValue, setEditValue] = useState('')
  const [saving, setSaving] = useState(false)
  const [rowFeedback, setRowFeedback] = useState<RowFeedback | null>(null)

  const searchRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  useEffect(() => {
    if (searchRef.current) clearTimeout(searchRef.current)
    searchRef.current = setTimeout(() => {
      setDebouncedSearch(search)
      setPage(0)
    }, 400)
    return () => { if (searchRef.current) clearTimeout(searchRef.current) }
  }, [search])

  const fetchShipments = useCallback(async () => {
    setLoading(true)
    try {
      const params = new URLSearchParams({
        page: String(page + 1),
        pageSize: String(pageSize),
        isLocker: 'true',
      })
      if (debouncedSearch) params.set('search', debouncedSearch)

      const res = await fetch(`/api/shipments?${params}`, {
        headers: { Authorization: `Bearer ${authToken}` },
      })
      const json = await res.json()
      setShipments(json.data ?? [])
      setTotal(json.total ?? 0)
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }, [page, pageSize, debouncedSearch, authToken])

  useEffect(() => { fetchShipments() }, [fetchShipments])

  const startEdit = useCallback((s: Shipment) => {
    setEditingId(s.id)
    setEditValue(s.trackingNumber ?? '')
    setRowFeedback(null)
  }, [])

  const saveTracking = useCallback(async (s: Shipment) => {
    if (!editValue.trim()) return
    setSaving(true)
    try {
      const res = await fetch('/api/shipments', {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${authToken}`,
        },
        body: JSON.stringify({ id: s.id, trackingNumber: editValue.trim() }),
      })
      const json = await res.json()
      if (!res.ok) throw new Error(json.message ?? 'Error')
      setRowFeedback({ id: s.id, msg: 'Guardado', ok: true })
      setEditingId(null)
      fetchShipments()
    } catch (err) {
      setRowFeedback({ id: s.id, msg: (err as Error).message, ok: false })
    } finally {
      setSaving(false)
      setTimeout(() => setRowFeedback(null), 3000)
    }
  }, [editValue, authToken, fetchShipments])

  return {
    shipments, total, page, setPage, pageSize, setPageSize, loading,
    search, setSearch,
    editingId, setEditingId, editValue, setEditValue, saving, rowFeedback,
    fetchShipments, startEdit, saveTracking
  }
