import { useState, useEffect, useCallback } from 'react'
import { useAuth } from '@/context/AuthContext'
import { ProfileData, ProfileFormData } from './types'
import { employeeClient } from '@/lib/api-client/employee'

export function useProfile() {
  const { token } = useAuth()
  const [profile, setProfile] = useState<ProfileData | null>(null)
  const [loading, setLoading] = useState(true)
  const [editing, setEditing] = useState(false)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [formData, setFormData] = useState<ProfileFormData>({
    firstName: '',
    lastName: '',
    timezone: ''
  })

  const fetchProfile = useCallback(async () => {
    if (!token) return
    try {
      setLoading(true)
      const data = await employeeClient.getProfile()
      setProfile(data)
      setFormData({
        firstName: data.firstName,
        lastName: data.lastName,
        timezone: data.timezone
      })
    } catch (err: any) {
      setError(err.message)
    } finally {
      setLoading(false)
    }
  }, [token])

  useEffect(() => {
    fetchProfile()
  }, [fetchProfile])

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!token) return
    try {
      setSaving(true)
      await employeeClient.updateProfile(formData)
      await fetchProfile()
      setEditing(false)
    } catch (err: any) {
      setError(err.message)
    } finally {
      setSaving(false)
    }
  }

  const jobTitle = profile?.contracts?.[0]?.job?.title || 'Sin cargo asignado'

  return {
    profile, loading, editing, setEditing, saving, error,
    formData, setFormData, fetchProfile, handleSave, jobTitle
  }
}

import { useState, useEffect, useCallback, useMemo } from 'react'
import { useAuth } from '@/context/AuthContext'
import { AttendanceRecord, TaskRecord } from './types'

function startOfWeek(): Date {
  const now = new Date()
  const monday = new Date(now)
  monday.setDate(now.getDate() - ((now.getDay() + 6) % 7))
  monday.setHours(0, 0, 0, 0)
  return monday
}

export function useReports() {
  const { user, token } = useAuth()
  const [records, setRecords] = useState<AttendanceRecord[]>([])
  const [tasks, setTasks] = useState<TaskRecord[]>([])
  const [loading, setLoading] = useState(true)

  const authHeaders = useMemo<HeadersInit>(() => {
    const h: Record<string, string> = {}
    if (token) h.Authorization = `Bearer ${token}`
    return h
  }, [token])

  const loadData = useCallback(async () => {
    if (!token || !user) return
    setLoading(true)
    try {
      const [histRes, taskRes] = await Promise.all([
        fetch('/api/attendance/history?limit=200', { headers: authHeaders, cache: 'no-store' }),
        fetch(`/api/tasks?employeeId=${user.id}&limit=200`, { headers: authHeaders }),
      ])

      const [histJson, taskJson] = await Promise.all([
        histRes.ok ? histRes.json() : { data: [] },
        taskRes.ok ? taskRes.json() : { data: [] },
      ])

      setRecords(histJson.data ?? [])
      setTasks(taskJson.data ?? taskJson ?? [])
    } catch {
      // keep empty state
    } finally {
      setLoading(false)
    }
  }, [token, user, authHeaders])

  useEffect(() => { loadData() }, [loadData])

  const weekStart = useMemo(startOfWeek, [])

  const hoursPerDay = useMemo<number[]>(() => {
    const arr = Array(7).fill(0)
    for (const r of records) {
      if (new Date(r.startedAt) < weekStart) continue
      const dayIdx = (new Date(r.startedAt).getDay() + 6) % 7
      arr[dayIdx] += Number(r.workedHours ?? 0)
    }
    return arr
  }, [records, weekStart])

  const totalAccumulated = useMemo(
    () => records.reduce((s, r) => s + Number(r.workedHours ?? 0), 0),
    [records],
  )

  const taskCounts = useMemo(() => {
    const counts: Record<string, number> = {}
    for (const t of tasks) {
      counts[t.status] = (counts[t.status] ?? 0) + 1
    }
    return counts
  }, [tasks])

  return {
    records, tasks, loading, loadData,
    hoursPerDay, totalAccumulated, taskCounts
  }
}

import { useState, useEffect, useCallback } from 'react'
import { useAuth } from '@/context/AuthContext'
import { Task, TaskStatus, AttendanceStatus } from './types'

export function useTasks() {
  const { user, token } = useAuth()
  const employeeId = user?.id ?? null

  const [tasks, setTasks] = useState<Task[]>([])
  const [loading, setLoading] = useState(true)
  const [actionError, setActionError] = useState<string | null>(null)
  const [modalOpen, setModalOpen] = useState(false)
  const [newTitle, setNewTitle] = useState('')
  const [newDesc, setNewDesc] = useState('')
  const [saving, setSaving] = useState(false)

  const [attendanceStatus, setAttendanceStatus] = useState<AttendanceStatus>(null)
  const canUpdate = attendanceStatus === 'OPEN' || attendanceStatus === 'PAUSED'

  const authHeaders = useCallback(
    (extra?: Record<string, string>): HeadersInit => {
      const h: Record<string, string> = { ...extra }
      if (token) h.Authorization = `Bearer ${token}`
      return h
    },
    [token],
  )

  const loadAttendance = useCallback(async () => {
    if (!token) return
    try {
      const res = await fetch(`/api/attendance/today?_=${Date.now()}`, {
        headers: authHeaders(),
        cache: 'no-store',
      })
      if (!res.ok) { setAttendanceStatus(null); return }
      const data = await res.json()
      setAttendanceStatus(data ? (data.status as AttendanceStatus) : null)
    } catch {
      setAttendanceStatus(null)
    }
  }, [token, authHeaders])

  const loadTasks = useCallback(async () => {
    if (!employeeId) return
    setLoading(true)
    try {
      const res = await fetch(
        `/api/tasks?employeeId=${employeeId}&limit=200&_=${Date.now()}`,
        { headers: authHeaders(), cache: 'no-store' },
      )
      if (!res.ok) { setTasks([]); return }
      const d = await res.json()
      setTasks(Array.isArray(d?.data) ? d.data : [])
    } catch {
      setTasks([])
    } finally {
      setLoading(false)
    }
  }, [employeeId, authHeaders])

  useEffect(() => {
    if (token) loadAttendance()
  }, [token, loadAttendance])

  useEffect(() => {
    if (employeeId) loadTasks()
  }, [employeeId, loadTasks])

  const createTask = async () => {
    if (!newTitle.trim() || !employeeId) return
    setSaving(true)
    try {
      const res = await fetch(`/api/tasks?adminId=${employeeId}`, {
        method: 'POST',
        headers: authHeaders({ 'Content-Type': 'application/json' }),
        cache: 'no-store',
        body: JSON.stringify({ title: newTitle.trim(), description: newDesc.trim() || null, employeeId }),
      })
      if (!res.ok) { alert('No se pudo crear la tarea'); return }
      setNewTitle('')
      setNewDesc('')
      setModalOpen(false)
      await loadTasks()
    } finally {
      setSaving(false)
    }
  }

  const updateStatus = async (id: number, status: TaskStatus) => {
    setActionError(null)
    setTasks(prev => prev.map(t => (t.id === id ? { ...t, status } : t)))
    try {
      const res = await fetch(`/api/tasks?id=${id}`, {
        method: 'PUT',
        headers: authHeaders({ 'Content-Type': 'application/json' }),
        cache: 'no-store',
        body: JSON.stringify({ status }),
      })
      if (!res.ok) {
        const err = await res.json().catch(() => ({}))
        setActionError(err.message || 'No se pudo actualizar el estado')
        await loadTasks()
      }
    } catch {
      setActionError('Error de red al actualizar la tarea')
      await loadTasks()
    }
  }

  return {
    employeeId, tasks, loading, actionError, setActionError,
    modalOpen, setModalOpen, newTitle, setNewTitle, newDesc, setNewDesc,
    saving, attendanceStatus, canUpdate, loadTasks, loadAttendance,
    createTask, updateStatus
  }
}

